const dateFormatElements=document.getElementsByClassName("date-format"),markdownFormatElements=document.getElementsByClassName("markdown-format"),twemojiFormatElements=document.getElementsByClassName("twemoji-format");for(let e of dateFormatElements)try{e.innerHTML=luxon.DateTime.fromISO(e.innerHTML).toFormat("fff")}catch(e){console.error(e)}for(let e of markdownFormatElements){let t=new showdown.Converter;try{e.innerHTML=t.makeHtml(e.innerHTML)}catch(e){console.error(e)}}for(let e of twemojiFormatElements)try{twemoji.parse(e)}catch(e){console.error(e)}function openNav(){document.getElementById("side-navigation").style.width="250px"}function closeNav(){document.getElementById("side-navigation").style.width="0"}document.onkeyup=function(e){"Escape"==e.key&&(document.body.innerHTML="",location.href="https://taiko.bui.pm/")};